    bool checkPalindromeFormation(string a, string b) {
        int n = a.size();
        for (int i = 0; i < n; i++) {
            string prefixA = a.substr(0, i + 1);
            string suffixA = a.substr(i + 1);
            string prefixB = b.substr(0, i + 1);
            string suffixB = b.substr(i + 1);
            if (isPalindrome(prefixA + suffixB) || isPalindrome(prefixB + suffixA)) {
                return true;
            }
        }
        return false;
    }
    bool isPalindrome(string s) {
        int l = 0, r = s.size() - 1;
        while (l < r) {
            if (s[l] != s[r]) {
                return false;
            }
            l++;
            r--;
        }
        return true;
    }
};```
